mapper.select:
SELECT * FROM coach_monthly_stats 
WHERE coach_id = #{coachId} 
ORDER BY year DESC, month DESC 
LIMIT #{months}

mapper.update:
UPDATE coach_monthly_stats
total_courses = #{totalCourses}, total_students = #{totalStudents}, attendance_rate = #{attendanceRate}, satisfaction_score = #{satisfactionScore}, total_hours = #{totalHours}, total_calories = #{totalCalories},
WHERE id = #{id}
